package com.wjx871.population.keypopulation;import com.wjx871.population.application.*;import com.wjx871.population.approval.*;import com.wjx871.population.audit.OperationLogService;import com.wjx871.population.common.BusinessException;import com.wjx871.population.material.*;import com.wjx871.population.reference.DataDictionaryService;import com.wjx871.population.security.*;import jakarta.servlet.http.HttpServletRequest;import java.time.*;import java.util.*;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service@RequiredArgsConstructor public class KeyPopulationService{private final KeyPopulationMapper mapper;private final ApplicationService applications;private final BusinessApplicationMapper applicationMapper;private final ApprovalService approvals;private final ApplicationMaterialMapper materials;private final ApprovalLogMapper approvalLogs;private final DataDictionaryService dictionaries;private final SensitiveDataMaskingService masking;private final OperationLogService audit;private final KeyPopulationTransactionHook hook;
@Transactional(readOnly=true)public Page<KeyPopulationView> search(Long person,String name,String idCard,String type,AttentionLevel level,KeyPopulationStatus status,Long dept,String region,LocalDate from,LocalDate to,Pageable p){DataScopeCriteria s=DataScopeCriteria.current();List<KeyPopulationView> rows=mapper.search(person,trim(name),trim(idCard),norm(type),level,status,dept,trim(region),from,to,s,p.getPageSize(),p.getOffset()).stream().map(x->KeyPopulationView.from(x,masking)).toList();return new PageImpl<>(rows,p,mapper.count(person,trim(name),trim(idCard),norm(type),level,status,dept,trim(region),from,to,s));}
@Transactional(readOnly=true)public KeyPopulationView get(Long id){return KeyPopulationView.from(scoped(id),masking);}@Transactional(readOnly=true)public Page<KeyPopulationView> byPerson(Long id,Pageable p){return search(id,null,null,null,null,null,null,null,null,null,p);}@Transactional(readOnly=true)public List<KeyPopulationHistory> history(Long id){scoped(id);return mapper.history(id);}
@Transactional public KeyApplicationView createRegister(RegisterApplicationRequest q,HttpServletRequest h){String status=scopedPerson(q.personId());activePerson(status);String type=norm(q.populationType());if(!dictionaries.enabled("KEY_POPULATION_TYPE",type))throw bad("重点人口类型不存在或已停用");if(mapper.countActive(q.personId(),type)>0)throw conflict("该人员已有同类型 ACTIVE 记录");if(mapper.countOpenRegister(q.personId(),type)>0)throw conflict("该人员已有同类型处理中建档申请");AuthenticatedUser u=CurrentUserContext.requireUser();ApplicationView a=applications.createSpecialized(new ApplicationRequest(BusinessType.KEY_POPULATION_REGISTER,q.title(),q.personId(),null,q.registerReason(),q.remark(),null),h);KeyPopulationApplication d=new KeyPopulationApplication();d.setApplicationId(a.applicationId());d.setOperationType(KeyOperationType.REGISTER);d.setPersonId(q.personId());d.setPopulationType(type);d.setAttentionLevel(q.attentionLevel());d.setReason(q.registerReason());d.setEventDate(q.registerDate());d.setResponsibleDepartmentId(q.responsibleDepartmentId()==null?u.departmentId():q.responsibleDepartmentId());d.setResponsibleUserId(q.responsibleUserId()==null?u.userId():q.responsibleUserId());d.setBusinessStatus(KeyApplicationStatus.DRAFT);d.setVersion(0);mapper.insertApplication(d);log("KEY_POPULATION_REGISTER_CREATE",a.applicationId(),h);return KeyApplicationView.from(applications.require(a.applicationId()),d);}
@Transactional public KeyApplicationView createRelease(Long recordId,ReleaseApplicationRequest q,HttpServletRequest h){KeyPopulationRecord r=scoped(recordId);if(r.getStatus()!=KeyPopulationStatus.ACTIVE)throw conflict("重点人口记录已解除");if(q.releaseDate().isBefore(r.getRegisterDate()))throw bad("解除日期不能早于建档日期");if(mapper.countOpenRelease(recordId)>0)throw conflict("该记录已有处理中解除申请");ApplicationView a=applications.createSpecialized(new ApplicationRequest(BusinessType.KEY_POPULATION_RELEASE,q.title(),r.getPersonId(),null,q.releaseReason(),q.remark(),null),h);KeyPopulationApplication d=new KeyPopulationApplication();d.setApplicationId(a.applicationId());d.setOperationType(KeyOperationType.RELEASE);d.setRecordId(recordId);d.setPersonId(r.getPersonId());d.setPopulationType(r.getPopulationType());d.setAttentionLevel(r.getAttentionLevel());d.setReason(q.releaseReason());d.setEventDate(q.releaseDate());d.setResponsibleDepartmentId(r.getResponsibleDepartmentId());d.setResponsibleUserId(r.getResponsibleUserId());d.setBusinessStatus(KeyApplicationStatus.DRAFT);d.setVersion(0);mapper.insertApplication(d);log("KEY_POPULATION_RELEASE_CREATE",a.applicationId(),h);return KeyApplicationView.from(applications.require(a.applicationId()),d);}
@Transactional(readOnly=true)public KeyPopulationDetailView detail(Long id,KeyOperationType expected){BusinessApplication a=applications.require(id);applications.assertCanView(a,CurrentUserContext.requireUser());KeyPopulationApplication d=mapper.findApplication(id).orElseThrow(()->notFound("重点人口申请详情不存在"));if(d.getOperationType()!=expected)throw bad("申请类型不匹配");return new KeyPopulationDetailView(KeyApplicationView.from(a,d),materials.selectByApplicationId(id).stream().map(MaterialView::from).toList(),approvalLogs.selectByApplicationId(id).stream().map(ApprovalLogView::from).toList());}
public void submit(Long id,HttpServletRequest h){approvals.submit(id,h);}
@Transactional public void executeRegister(Long id,KeyExecuteRequest q,HttpServletRequest h){AuthenticatedUser u=CurrentUserContext.requireUser();BusinessApplication a=approved(id,BusinessType.KEY_POPULATION_REGISTER,u);KeyPopulationApplication d=mapper.lockApplication(id).orElseThrow(()->notFound("重点人口申请详情不存在"));requireExecutable(d,KeyOperationType.REGISTER,q.version());activePerson(mapper.personStatus(d.getPersonId()).orElseThrow(()->notFound("人员不存在")));if(mapper.countActive(d.getPersonId(),d.getPopulationType())>0)throw conflict("该人员已有同类型 ACTIVE 记录");KeyPopulationRecord r=new KeyPopulationRecord();r.setPersonId(d.getPersonId());r.setPopulationType(d.getPopulationType());r.setAttentionLevel(d.getAttentionLevel());r.setRegisterReason(d.getReason());r.setRegisterDate(d.getEventDate());r.setResponsibleDepartmentId(d.getResponsibleDepartmentId());r.setResponsibleUserId(d.getResponsibleUserId());r.setStatus(KeyPopulationStatus.ACTIVE);r.setSourceApplicationId(id);r.setVersion(0);mapper.insertRecord(r);hook.afterRecordChange();history(r,"REGISTERED",null,"ACTIVE",d.getReason(),id,u.userId());hook.afterHistoryInsert();complete(a,d,u,id,"KEY_POPULATION_REGISTER_EXECUTE",h);}
@Transactional public void executeRelease(Long id,KeyExecuteRequest q,HttpServletRequest h){AuthenticatedUser u=CurrentUserContext.requireUser();BusinessApplication a=approved(id,BusinessType.KEY_POPULATION_RELEASE,u);KeyPopulationApplication d=mapper.lockApplication(id).orElseThrow(()->notFound("重点人口申请详情不存在"));requireExecutable(d,KeyOperationType.RELEASE,q.version());KeyPopulationRecord r=mapper.lockRecord(d.getRecordId()).orElseThrow(()->notFound("重点人口记录不存在"));if(r.getStatus()!=KeyPopulationStatus.ACTIVE)throw conflict("重点人口记录已解除");if(d.getEventDate().isBefore(r.getRegisterDate()))throw bad("解除日期不能早于建档日期");if(mapper.releaseRecord(r.getRecordId(),d.getReason(),d.getEventDate(),r.getVersion())==0)ApplicationService.conflict();hook.afterRecordChange();history(r,"RELEASED","ACTIVE","RELEASED",d.getReason(),id,u.userId());hook.afterHistoryInsert();complete(a,d,u,id,"KEY_POPULATION_RELEASE_EXECUTE",h);}
private void complete(BusinessApplication a,KeyPopulationApplication d,AuthenticatedUser u,Long id,String op,HttpServletRequest h){if(mapper.updateApplicationStatus(id,KeyApplicationStatus.APPROVED,KeyApplicationStatus.COMPLETED,d.getVersion())==0)ApplicationService.conflict();if(applicationMapper.updateStatus(id,ApplicationStatus.APPROVED,ApplicationStatus.COMPLETED,a.getVersion())==0)ApplicationService.conflict();approvalLogs.insert(ApprovalLog.of(null,id,ApprovalAction.EXECUTE,"APPROVED","COMPLETED",u.userId(),"重点人口业务显式执行完成",audit.clientIp(h)));log(op,id,h);}private void history(KeyPopulationRecord r,String event,String prev,String next,String reason,Long app,Long user){KeyPopulationHistory x=new KeyPopulationHistory();x.setRecordId(r.getRecordId());x.setPersonId(r.getPersonId());x.setEventType(event);x.setPreviousStatus(prev);x.setNewStatus(next);x.setReason(reason);x.setSourceApplicationId(app);x.setOperatorId(user);x.setSnapshotJson("{\"populationType\":\""+r.getPopulationType()+"\",\"attentionLevel\":\""+r.getAttentionLevel()+"\",\"status\":\""+next+"\"}");mapper.insertHistory(x);}private BusinessApplication approved(Long id,BusinessType type,AuthenticatedUser u){BusinessApplication a=applications.require(id);if(a.getBusinessType()!=type||a.getStatus()!=ApplicationStatus.APPROVED)throw conflict("申请尚未批准或已执行");assertScope(a,u);return a;}private void requireExecutable(KeyPopulationApplication d,KeyOperationType op,Integer version){if(d.getOperationType()!=op||d.getBusinessStatus()!=KeyApplicationStatus.APPROVED)throw conflict("专业申请尚未批准或已执行");if(!Objects.equals(d.getVersion(),version))ApplicationService.conflict();}private String scopedPerson(Long id){return mapper.personScopedStatus(id,DataScopeCriteria.current()).orElseThrow(()->new BusinessException(HttpStatus.NOT_FOUND,"人员不存在或无权访问"));}private KeyPopulationRecord scoped(Long id){return mapper.findScopedRecord(id,DataScopeCriteria.current()).orElseThrow(()->notFound("重点人口记录不存在"));}private void activePerson(String s){if("CANCELLED".equals(s)||"DECEASED".equals(s))throw conflict("已注销或死亡人员不能建档");}private void assertScope(BusinessApplication a,AuthenticatedUser u){if(a.getApplicantUserId().equals(u.userId())||u.dataScope()==DataScope.ALL)return;if(u.dataScope()==DataScope.DEPARTMENT&&Objects.equals(a.getApplicantDepartmentId(),u.departmentId()))return;if(u.dataScope()==DataScope.REGION&&Objects.equals(a.getApplicantRegionCode(),u.regionCode()))return;throw new BusinessException(HttpStatus.FORBIDDEN,"超出重点人口数据范围");}private void log(String op,Long id,HttpServletRequest h){audit.recordTransactional(CurrentUserContext.requireUser().userId(),op,"KEY_POPULATION",String.valueOf(id),h);}private String norm(String x){x=trim(x);return x==null?null:x.toUpperCase(Locale.ROOT);}private String trim(String x){return x==null||x.isBlank()?null:x.trim();}private BusinessException bad(String m){return new BusinessException(HttpStatus.BAD_REQUEST,m);}private BusinessException conflict(String m){return new BusinessException(HttpStatus.CONFLICT,m);}private BusinessException notFound(String m){return new BusinessException(HttpStatus.NOT_FOUND,m);}}
